import { GoogleGenAI, Type, Modality, Content, Part } from "@google/genai";
import { PageBlueprint, Character, Language } from '../types';

if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const fullStorySchema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: 'A short, catchy title for the story in the original story language.'
    },
    pages: {
      type: Type.ARRAY,
      description: 'An array of 8 to 10 story pages that form a complete narrative.',
      items: {
        type: Type.OBJECT,
        properties: {
          pageText: {
            type: Type.STRING,
            description: 'A short segment of the story text for a single page. Must be in the original story language.',
          },
          imagePrompt: {
            type: Type.STRING,
            description: 'A vivid, descriptive prompt in English for an AI image generator.',
          },
          animation: {
            type: Type.OBJECT,
            properties: {
              keyword: { type: Type.STRING },
              type: {
                type: Type.STRING,
                enum: ['glow', 'bounce', 'shake', 'spin', 'float'],
              },
            },
          },
        },
        required: ['pageText', 'imagePrompt'],
      },
      minItems: 8,
      maxItems: 10,
    },
  },
  required: ['title', 'pages'],
};

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

async function withRetry<T>(fn: () => Promise<T>, retries = 3, baseDelay = 2000, operationName = "API Call"): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isQuotaError = 
        error.status === 429 || 
        error.status === 503 || 
        (error.message && (error.message.includes('429') || error.message.includes('RESOURCE_EXHAUSTED') || error.message.includes('quota')));

    if (retries > 0 && isQuotaError) {
      console.warn(`[${operationName}] Quota hit or busy. Retrying in ${baseDelay}ms... (${retries} attempts left)`);
      await sleep(baseDelay);
      return withRetry(fn, retries - 1, baseDelay * 2, operationName);
    }
    throw error;
  }
}

export async function generateFullStory(
  character: Character,
  language: Language,
  storyPrompt: string,
): Promise<{ title: string; pages: PageBlueprint[] }> {
  const langName = language === 'am' ? 'Amharic' : 'English';
  const systemInstruction = `You are a master storyteller for children. Write a story about ${character.name} based on: ${storyPrompt}. Language: ${langName}. Return JSON.`;

  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ role: 'user', parts: [{ text: `Write a story about ${character.name} based on: ${storyPrompt}` }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: fullStorySchema,
      },
    });
    return JSON.parse(response.text.trim());
  }, 3, 1000, "Generate Story Text");
}

export async function generateSpeech(text: string): Promise<string> {
  return withRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
  }, 3, 1000, "Generate Speech");
}

export async function cartoonizeImage(base64Image: string): Promise<string> {
  return withRetry(async () => {
    const mimeType = base64Image.substring(5, base64Image.indexOf(';'));
    const data = base64Image.substring(base64Image.indexOf(',') + 1);
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ inlineData: { mimeType, data } }, { text: "Cartoonize this character for a storybook." }],
      },
      config: { responseModalities: [Modality.IMAGE] },
    });
    const part = response.candidates[0].content.parts.find(p => p.inlineData);
    if (!part) throw new Error("No image generated");
    return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
  }, 3, 2000, "Cartoonize Image");
}

export async function generateImage(prompt: string, characterImage: string | null): Promise<string> {
  return withRetry(async () => {
    const parts: Part[] = [];
    if (characterImage) {
      const mimeType = characterImage.substring(5, characterImage.indexOf(';'));
      const data = characterImage.substring(characterImage.indexOf(',') + 1);
      parts.push({ inlineData: { mimeType, data } });
      parts.push({ text: `Storybook illustration of the character in this scene: ${prompt}` });
    } else {
      parts.push({ text: `Storybook illustration: ${prompt}` });
    }
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: { responseModalities: [Modality.IMAGE] },
    });
    const part = response.candidates[0].content.parts.find(p => p.inlineData);
    if (!part) throw new Error("No image data");
    return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
  }, 5, 3000, "Generate Illustration");
}

/**
 * Generates a cinematic video trailer for the story climax using Veo 3.1
 */
export async function generateStoryVideo(prompt: string, onStatusUpdate?: (msg: string) => void): Promise<string> {
  const aiInstance = new GoogleGenAI({ apiKey: process.env.API_KEY });

  onStatusUpdate?.("Initiating video generation engine...");
  let operation = await aiInstance.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic 3D animation for kids: ${prompt}. High quality, vibrant colors, magical atmosphere.`,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  onStatusUpdate?.("Processing frames (this may take 1-2 minutes)...");
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 8000));
    operation = await aiInstance.operations.getVideosOperation({ operation: operation });
    onStatusUpdate?.("Adding magical effects to your trailer...");
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Page, Language } from '../types';
import { generateSpeech, generateStoryVideo } from '../services/geminiService';

// --- Audio Helper Functions ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
): Promise<AudioBuffer> {
  const sampleRate = 24000;
  const numChannels = 1;
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < frameCount; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  return buffer;
}

interface PageContentProps {
  page: Page;
  language: Language;
  playbackState: 'stopped' | 'playing' | 'paused';
  onPlay: (speed: number) => void;
  onPause: () => void;
  onResume: () => void;
  onStop: () => void;
  highlightedWordIndex: number;
  isLoadingAudio: boolean;
}

const renderInteractiveText = (page: Page, highlightedWordIndex: number, language: Language, onPausePlayback: () => void) => {
  if (!page.pageText) return null;
  const words = page.pageText.split(/\s+/).filter(Boolean);
  const animatableKeyword = page.animation?.keyword?.toLowerCase();

  const speakWord = (text: string) => {
    onPausePlayback();
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel(); 
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = language === 'am' ? 'am-ET' : 'en-US';
    utterance.rate = 0.9;
    window.speechSynthesis.speak(utterance);
  };

  return (
    <p className={`text-slate-700 text-xl leading-relaxed ${language === 'am' ? 'font-amharic' : ''} select-none`}>
      {words.map((word, index) => {
        const cleanWord = word.replace(/[.,!?;:"'()]/g, '').toLowerCase();
        const isAnimatable = animatableKeyword && cleanWord === animatableKeyword;
        const isCurrentWord = index === highlightedWordIndex;

        return (
          <span 
            key={index} 
            className={`transition-all duration-300 inline-block px-1 ${isCurrentWord ? 'scale-110 font-bold text-blue-600 bg-yellow-200 rounded shadow-sm' : 'bg-transparent'}`}
            onDoubleClick={(e) => { e.stopPropagation(); speakWord(cleanWord); }}
          >
            {word}{' '}
          </span>
        );
      })}
    </p>
  );
};

const PageContent: React.FC<PageContentProps> = React.memo(({ 
  page, language, playbackState, onPlay, onPause, onResume, onStop, highlightedWordIndex, isLoadingAudio 
}) => {
  return (
    <>
      <img src={page.imageUrl} alt="Story illustration" className="w-full h-1/2 object-cover rounded-lg mb-4 shadow" />
      <div className={`flex-grow overflow-y-auto pr-2 relative ${highlightedWordIndex > -1 ? 'is-reading' : ''}`}>
        <div className="flex flex-col gap-3">
           <div className="flex flex-wrap items-center gap-2 mb-1 no-print">
             {isLoadingAudio ? (
                <div className="flex items-center gap-2 text-blue-600 bg-blue-50 px-3 py-1 rounded-full">
                  <span className="animate-spin text-xs">🌀</span>
                  <span className="text-xs font-bold">Loading Voice...</span>
                </div>
             ) : playbackState === 'stopped' ? (
               <button onClick={(e) => { e.stopPropagation(); onPlay(1); }} className="px-4 py-1.5 rounded-full bg-blue-600 text-white hover:bg-blue-700 transition-colors text-sm font-bold shadow-sm">
                 Play Page
               </button>
             ) : (
               <>
                 <button onClick={(e) => { e.stopPropagation(); playbackState === 'playing' ? onPause() : onResume(); }} className="px-4 py-1.5 rounded-full bg-yellow-400 text-slate-800 hover:bg-yellow-500 transition-colors text-sm font-bold shadow-sm">
                    {playbackState === 'playing' ? 'Pause' : 'Resume'}
                 </button>
                 <button onClick={(e) => { e.stopPropagation(); onStop(); }} className="px-4 py-1.5 rounded-full bg-red-100 text-red-700 hover:bg-red-200 transition-colors text-sm font-bold">
                   Stop
                 </button>
               </>
             )}
           </div>
           <div className="flex-grow">
            {renderInteractiveText(page, highlightedWordIndex, language, onPause)}
           </div>
        </div>
      </div>
    </>
  );
});

interface StorybookViewerProps {
  pages: Page[];
  pageAudio: (string | null)[];
  onExit: () => void;
  onSaveStory: () => void;
  language: Language;
  isViewingSaved: boolean;
  isSaved: boolean;
  storyTitle?: string;
}

const StorybookViewer: React.FC<StorybookViewerProps> = ({ pages, pageAudio, language, onExit, onSaveStory, isViewingSaved, isSaved, storyTitle }) => {
  const [currentSpread, setCurrentSpread] = useState(0);
  const [audioBuffers, setAudioBuffers] = useState<(AudioBuffer | null)[]>([]);
  const [activePageIndex, setActivePageIndex] = useState<number | null>(null);
  const [playbackState, setPlaybackState] = useState<'stopped' | 'playing' | 'paused'>('stopped');
  const [activeSpeed, setActiveSpeed] = useState<number>(1);
  const [highlightedWordIndex, setHighlightedWordIndex] = useState<number>(-1);
  const [loadingAudioIndex, setLoadingAudioIndex] = useState<number | null>(null);
  const [isAutoPlay, setIsAutoPlay] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoLoadingMsg, setVideoLoadingMsg] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const startTimeRef = useRef<number>(0);

  useEffect(() => {
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const decodeAllAudio = async () => {
        if (!audioContextRef.current) return;
        const decodedBuffers = await Promise.all(pageAudio.map(audioBase64 => {
            if (!audioBase64 || !audioContextRef.current) return null;
            try {
                const bytes = decode(audioBase64.split(',')[1]);
                return decodeAudioData(bytes, audioContextRef.current);
            } catch (e) { return null; }
        }));
        setAudioBuffers(decodedBuffers);
    };
    decodeAllAudio();
    return () => { hardStop(); audioContextRef.current?.close(); };
  }, [pageAudio]);

  const hardStop = useCallback(() => {
    if (sourceNodeRef.current) {
        sourceNodeRef.current.onended = null;
        try { sourceNodeRef.current.stop(); } catch(e) {}
        sourceNodeRef.current = null;
    }
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
    setActivePageIndex(null);
    setPlaybackState('stopped');
    setHighlightedWordIndex(-1);
  }, []);

  const handleNext = useCallback(() => {
    setCurrentSpread(s => {
        const total = Math.ceil(pages.length / 2);
        return Math.min(s + 1, total);
    });
  }, [pages.length]);

  const playPageAudio = useCallback(async (pageIndex: number, speed: number = 1) => {
    if (activePageIndex !== null) hardStop();
    let buffer = audioBuffers[pageIndex];
    if (!buffer && pages[pageIndex]) {
        try {
            setLoadingAudioIndex(pageIndex);
            const newAudioBase64 = await generateSpeech(pages[pageIndex].pageText);
            const bytes = decode(newAudioBase64);
            if (audioContextRef.current) {
                buffer = await decodeAudioData(bytes, audioContextRef.current);
                setAudioBuffers(prev => { const n = [...prev]; n[pageIndex] = buffer; return n; });
            }
        } catch(e) { return; } finally { setLoadingAudioIndex(null); }
    }
    if (!buffer || !audioContextRef.current) return;
    if (audioContextRef.current.state === 'suspended') await audioContextRef.current.resume();

    setActivePageIndex(pageIndex);
    setActiveSpeed(speed);
    setPlaybackState('playing');
    const sourceNode = audioContextRef.current.createBufferSource();
    sourceNode.buffer = buffer;
    sourceNode.playbackRate.value = speed;
    sourceNode.connect(audioContextRef.current.destination);
    sourceNode.start();
    sourceNodeRef.current = sourceNode;
    startTimeRef.current = audioContextRef.current.currentTime;
    const words = pages[pageIndex].pageText.split(/\s+/).filter(Boolean);
    const duration = buffer.duration;

    const animate = () => {
        if (!audioContextRef.current || !sourceNodeRef.current) return;
        const audioConsumed = (audioContextRef.current.currentTime - startTimeRef.current) * speed;
        if (audioConsumed >= duration) { setHighlightedWordIndex(-1); return; }
        setHighlightedWordIndex(Math.min(Math.floor((audioConsumed / duration) * words.length), words.length - 1));
        animationFrameRef.current = requestAnimationFrame(animate);
    };
    animationFrameRef.current = requestAnimationFrame(animate);

    sourceNode.onended = () => {
        hardStop();
        if (isAutoPlay) {
            setTimeout(() => {
                const isLeftPage = pageIndex % 2 === 0;
                if (isLeftPage && pages[pageIndex + 1]) {
                    playPageAudio(pageIndex + 1, speed);
                } else if (pageIndex < pages.length - 1) {
                    handleNext();
                    setTimeout(() => playPageAudio(pageIndex + 1, speed), 1600);
                }
            }, 1000);
        }
    };
  }, [activePageIndex, audioBuffers, pages, hardStop, isAutoPlay, handleNext]);

  const pauseAudio = () => { audioContextRef.current?.suspend(); setPlaybackState('paused'); };
  const resumeAudio = () => { audioContextRef.current?.resume(); setPlaybackState('playing'); };

  const handleGenerateTrailer = async () => {
    try {
        setVideoLoadingMsg("Preparing the cinematic trailer...");
        const climaxPage = pages[Math.floor(pages.length * 0.7)];
        const url = await generateStoryVideo(climaxPage.pageText, setVideoLoadingMsg);
        setVideoUrl(url);
    } catch (e) {
        alert("Video generation limit reached for today. Try again tomorrow!");
    } finally {
        setVideoLoadingMsg(null);
    }
  };

  const papers = useMemo(() => {
    const p = [];
    for (let i = 0; i < pages.length; i += 2) {
      p.push({
        front: { page: pages[i], pageIndex: i },
        back: pages[i + 1] ? { page: pages[i + 1], pageIndex: i + 1 } : null
      });
    }
    return p;
  }, [pages]);

  return (
    <div className="flex flex-col items-center w-full relative pb-20">
      {/* Home Button */}
      <button onClick={onExit} className="absolute top-[-3rem] left-0 bg-white/90 px-4 py-2 rounded-full shadow font-bold z-50 no-print hover:bg-white">
         🏠 Home
      </button>

      <div className="book-container mt-8">
        <div className="book">
          <div className="paper back-cover" style={{ zIndex: 0 }}></div>
          {papers.map((paper, index) => {
            const isFlipped = currentSpread > index;
            const zIndex = isFlipped ? (papers.length + index) : (papers.length - index);
            return (
                <div key={index} className={`paper ${isFlipped ? 'flipped' : ''}`} style={{ zIndex }}>
                  <div className="page-content front">
                    {paper.front && (
                        <PageContent 
                            page={paper.front.page} language={language} 
                            playbackState={activePageIndex === paper.front.pageIndex ? playbackState : 'stopped'}
                            isLoadingAudio={loadingAudioIndex === paper.front.pageIndex}
                            onPlay={(s) => playPageAudio(paper.front!.pageIndex, s)}
                            onPause={pauseAudio} onResume={resumeAudio} onStop={hardStop}
                            highlightedWordIndex={activePageIndex === paper.front.pageIndex ? highlightedWordIndex : -1}
                        />
                    )}
                  </div>
                  <div className="page-content back">
                    {paper.back && (
                        <PageContent 
                            page={paper.back.page} language={language} 
                            playbackState={activePageIndex === paper.back.pageIndex ? playbackState : 'stopped'}
                            isLoadingAudio={loadingAudioIndex === paper.back.pageIndex}
                            onPlay={(s) => playPageAudio(paper.back!.pageIndex, s)}
                            onPause={pauseAudio} onResume={resumeAudio} onStop={hardStop}
                            highlightedWordIndex={activePageIndex === paper.back.pageIndex ? highlightedWordIndex : -1}
                        />
                    )}
                  </div>
                </div>
            );
          })}
        </div>
      </div>

      <div className="flex flex-col items-center gap-6 mt-12 w-full no-print">
        <div className="flex items-center gap-4 bg-white p-3 rounded-2xl shadow-md border border-slate-100">
            <button onClick={() => setCurrentSpread(s => Math.max(s - 1, 0))} disabled={currentSpread === 0} className="nav-button">Prev</button>
            <div className="flex flex-col items-center px-6">
                <span className="font-bold text-slate-700">Page {currentSpread * 2 || 'Cover'}</span>
                <label className="flex items-center gap-2 mt-1 cursor-pointer select-none">
                    <input type="checkbox" checked={isAutoPlay} onChange={e => setIsAutoPlay(e.target.checked)} className="w-4 h-4 rounded text-blue-600" />
                    <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Auto-Play Mode</span>
                </label>
            </div>
            <button onClick={handleNext} disabled={currentSpread >= papers.length} className="nav-button">Next</button>
        </div>

        {currentSpread >= papers.length && (
            <div className="bg-white p-8 rounded-3xl shadow-2xl space-y-6 text-center animate-fade-in w-full max-w-xl border-4 border-blue-50">
                <h2 className="text-4xl font-extrabold text-blue-600">The End!</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <button onClick={onSaveStory} disabled={isSaved} className="bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg disabled:opacity-50">
                        {isSaved ? '✅ Story Saved' : '💾 Save Story'}
                    </button>
                    <button onClick={() => window.print()} className="bg-slate-800 text-white font-bold py-3 rounded-xl hover:bg-slate-900 shadow-lg">
                        📄 Print as PDF
                    </button>
                    <button onClick={handleGenerateTrailer} disabled={!!videoLoadingMsg || !!videoUrl} className="bg-gradient-to-r from-purple-600 to-blue-600 text-white font-bold py-3 rounded-xl hover:opacity-90 shadow-lg disabled:opacity-50 sm:col-span-2">
                        {videoLoadingMsg ? '🎬 Processing Trailer...' : videoUrl ? '✅ Trailer Ready' : '🎥 Generate Video Trailer'}
                    </button>
                </div>

                {videoLoadingMsg && (
                    <div className="p-4 bg-blue-50 rounded-xl animate-pulse">
                        <p className="text-blue-700 font-bold">{videoLoadingMsg}</p>
                    </div>
                )}

                {videoUrl && (
                    <div className="mt-4 space-y-3">
                        <video controls src={videoUrl} className="w-full rounded-xl shadow-inner bg-black" />
                        <a href={videoUrl} download="story-trailer.mp4" className="inline-block text-blue-600 font-bold hover:underline">Download MP4</a>
                    </div>
                )}
            </div>
        )}
      </div>
    </div>
  );
};

export default StorybookViewer;

import React, { useState, useCallback, useEffect } from 'react';
import { Page, Character, Language, SavedStory, PageBlueprint, SavedStoryPage } from './types';
import { generateFullStory, generateImage, generateSpeech, cartoonizeImage } from './services/geminiService';
import StoryInput from './components/StoryInput';
import StorybookViewer from './components/StorybookViewer';
import Loader from './components/Loader';
import SavedStories from './components/SavedStories';

const STORAGE_KEY = 'ai_storybook_saved_stories';
const QUOTA_LOCKOUT_KEY = 'gemini_quota_lockout_timestamp';
const LOCKOUT_DURATION = 1000 * 60 * 60 * 12;

function getSavedStories(): SavedStory[] {
  try {
    const storiesJson = localStorage.getItem(STORAGE_KEY);
    return storiesJson ? JSON.parse(storiesJson) : [];
  } catch (error) { return []; }
}

function saveStoryToStorage(story: Omit<SavedStory, 'id' | 'createdAt'>): SavedStory {
  const stories = getSavedStories();
  const newStory: SavedStory = { ...story, id: Date.now().toString(), createdAt: Date.now() };
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify([newStory, ...stories]));
    return newStory;
  } catch (error) {
    const strippedPages = newStory.pages.map(p => ({ pageText: p.pageText, imagePrompt: p.imagePrompt, animation: p.animation }));
    const strippedStory = { ...newStory, pages: strippedPages };
    localStorage.setItem(STORAGE_KEY, JSON.stringify([strippedStory, ...stories]));
    alert("Story saved text-only due to storage limits.");
    return strippedStory;
  }
}

function deleteStoryFromStorage(storyId: string): void {
  const stories = getSavedStories().filter(s => s.id !== storyId);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(stories));
}

