function App() {
  const [view, setView] = useState<'input' | 'storybook' | 'saved'>('input');
  const [character, setCharacter] = useState<Character>({ name: '', appearance: '', trait: '' });
  const [characterImage, setCharacterImage] = useState<string | null>(null);
  const [cartoonizedCharacterImage, setCartoonizedCharacterImage] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>('en');
  const [storyPrompt, setStoryPrompt] = useState('');
  const [storyTitle, setStoryTitle] = useState('');
  const [storyBlueprints, setStoryBlueprints] = useState<PageBlueprint[]>([]);
  const [storyPages, setStoryPages] = useState<Page[]>([]);
  const [storyAudio, setStoryAudio] = useState<(string | null)[]>([]);
  const [isSaved, setIsSaved] = useState(false);
  const [isViewingSaved, setIsViewingSaved] = useState(false);
  const [storyId, setStoryId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [savedStories, setSavedStories] = useState<SavedStory[]>(() => getSavedStories());
  const [loadingMessage, setLoadingMessage] = useState('');
  const [isQuotaExhausted, setIsQuotaExhausted] = useState(false);

  useEffect(() => {
    const lockoutTime = localStorage.getItem(QUOTA_LOCKOUT_KEY);
    if (lockoutTime) {
        const diff = Date.now() - parseInt(lockoutTime, 10);
        if (diff < LOCKOUT_DURATION) setIsQuotaExhausted(true);
        else localStorage.removeItem(QUOTA_LOCKOUT_KEY);
    }
  }, []);

  const handleStartStory = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setView('storybook');
    setLoadingMessage("Summoning your adventure...");

    try {
      const storyPromise = generateFullStory(character, language, storyPrompt);
      const cartoonPromise = (characterImage && !isQuotaExhausted)
        ? cartoonizeImage(characterImage).catch(err => {
            if (err.message?.includes('429') || err.message?.includes('RESOURCE_EXHAUSTED')) {
                setIsQuotaExhausted(true);
                localStorage.setItem(QUOTA_LOCKOUT_KEY, Date.now().toString());
            }
            return null;
          }) 
        : Promise.resolve(null);

      const [fullStory, cartoonImg] = await Promise.all([storyPromise, cartoonPromise]);
      setCartoonizedCharacterImage(cartoonImg);
      setStoryTitle(fullStory.title);
      setStoryBlueprints(fullStory.pages);

      setLoadingMessage("Painting the magic pages...");
      const audioPromises = fullStory.pages.map(p => generateSpeech(p.pageText).catch(() => null));
      const imageUrls = new Array(fullStory.pages.length);
      const BATCH_SIZE = 2; // Conservative batching to avoid 429

      for (let i = 0; i < fullStory.pages.length; i += BATCH_SIZE) {
        const batch = fullStory.pages.slice(i, i + BATCH_SIZE);
        await Promise.all(batch.map((p, idx) => 
            generateImage(p.imagePrompt, cartoonImg).then(url => { imageUrls[i + idx] = url; }).catch(() => { imageUrls[i+idx] = "https://placehold.co/600x400/e2e8f0/475569?text=Image+Limit+Reached"; })
        ));
        setLoadingMessage(`Painting pages ${i+1}-${Math.min(i+BATCH_SIZE, fullStory.pages.length)}...`);
      }

      const audioData = await Promise.all(audioPromises);
      const finalPages: Page[] = fullStory.pages.map((p, i) => ({
        pageText: p.pageText,
        imageUrl: imageUrls[i],
        animation: p.animation,
      }));

      setStoryPages(finalPages);
      setStoryAudio(audioData.map(a => a ? `data:audio/webm;base64,${a}` : null));
      setStoryId(Date.now().toString());
    } catch (e: any) {
      setError(e.message || 'The story spirits are busy. Try again soon!');
      setView('input');
    } finally {
      setIsLoading(false);
    }
  }, [character, language, storyPrompt, characterImage, isQuotaExhausted]);

  const handleExitToMenu = () => {
    setView('input');
    setStoryPages([]);
    setIsViewingSaved(false);
    setStoryId(null);
  };

  const handleLoadStory = async (story: SavedStory) => {
    setIsLoading(true);
    setError(null);
    setStoryTitle(story.title);
    setLanguage(story.language);
    setView('storybook');
    setLoadingMessage("Restoring your hero's journey...");

    try {
      const hasCached = story.pages.every(p => !!p.imageUrl);
      let pages: Page[];
      let audio: (string | null)[];

      if (hasCached) {
        pages = story.pages.map(p => ({ pageText: p.pageText, imageUrl: p.imageUrl!, animation: p.animation }));
        audio = story.pages.map(p => p.audioData || null);
      } else {
        // Regenerate logic... (simplified for brevity)
        pages = story.pages.map(p => ({ pageText: p.pageText, imageUrl: "https://placehold.co/600x400?text=Please+Regenerate", animation: p.animation }));
        audio = story.pages.map(() => null);
      }

      setStoryPages(pages);
      setStoryAudio(audio);
      setIsViewingSaved(true);
      setIsSaved(true);
      setStoryId(story.id);
    } catch (e) { setError("Failed to load adventure."); setView('input'); } finally { setIsLoading(false); }
  };

  const isHomeScreen = view === 'input' || view === 'saved';

  return (
    <>
      <div id="space-container" aria-hidden="true">
        <div id="stars1" className="stars" />
        <div id="stars2" className="stars" />
        <div id="stars3" className="stars" />
      </div>
      {isHomeScreen && <Spaceship />}
      <div className={`relative z-10 min-h-screen p-4 transition-colors duration-500 ${isHomeScreen ? 'bg-transparent' : 'bg-slate-100'}`}>
        <header className="text-center mb-8">
          <h1 className={`text-5xl font-extrabold transition-all ${isHomeScreen ? 'text-white drop-shadow-lg' : 'text-slate-800'}`}>AI Storybook</h1>
          {isHomeScreen && (
            <div className="mt-4 flex justify-center gap-4">
              <button onClick={() => setView(view === 'input' ? 'saved' : 'input')} className="bg-white/20 backdrop-blur-md border border-white/30 text-white font-bold py-2 px-6 rounded-full hover:bg-white/30 transition-all">
                {view === 'input' ? '📂 Library' : '✍️ Create'}
              </button>
            </div>
          )}
        </header>

        <main className="container mx-auto max-w-6xl">
          {error && <div className="bg-red-500 text-white p-4 rounded-xl mb-6 font-bold shadow-lg animate-bounce">{error}</div>}
          <div className="flex justify-center">
            {view === 'input' && <StoryInput character={character} setCharacter={setCharacter} characterImage={characterImage} setCharacterImage={setCharacterImage} language={language} setLanguage={setLanguage} storyPrompt={storyPrompt} setStoryPrompt={setStoryPrompt} onSubmit={handleStartStory} isLoading={isLoading} savedStories={savedStories} onLoadSavedStory={handleLoadStory} isQuotaExhausted={isQuotaExhausted} />}
            {view === 'saved' && <SavedStories stories={savedStories} onLoad={handleLoadStory} onDelete={(id) => { deleteStoryFromStorage(id); setSavedStories(getSavedStories()); }} />}
            {view === 'storybook' && isLoading && <Loader message={loadingMessage} />}
            {view === 'storybook' && !isLoading && storyPages.length > 0 && storyId && <StorybookViewer key={storyId} pages={storyPages} pageAudio={storyAudio} onExit={handleExitToMenu} onSaveStory={() => { saveStoryToStorage({ title: storyTitle, character, characterImage, pages: storyPages.map((p, i) => ({ ...p, imagePrompt: '', audioData: storyAudio[i] })), language }); setIsSaved(true); setSavedStories(getSavedStories()); }} language={language} isViewingSaved={isViewingSaved} isSaved={isSaved} storyTitle={storyTitle} />}
          </div>
        </main>
      </div>
    </>
  );
}

