          pageText: blueprint.pageText,
          imageUrl: imageUrl,
          animation: blueprint.animation,
        });
        finalAudio.push(audioData);

        // Mandatory rest to prevent "Burst Rate" 429 triggers
        await new Promise(r => setTimeout(r, 1200));
      }

      setStoryPages(finalPages);
      setStoryAudio(finalAudio);
      setStoryId(Date.now().toString());
    } catch (e: any) {
      console.error("Critical story error:", e);
      setError('The magic is a bit slow today! Please try a shorter story or wait a moment.');
      setView('input');
    } finally {
      setIsLoading(false);
    }
  }, [character, language, storyPrompt, characterImage, isQuotaExhausted]);

