      setIsViewingSaved(true);
      setIsSaved(true);
      setStoryId(story.id);
    } catch (e) { 
      setError("Failed to load adventure."); 
      setView('input'); 
    } finally { 
      setIsLoading(false); 
    }
  };

  const isHomeScreen = view === 'input' || view === 'saved';

  return (
